import React from "react";
import { MainLayout } from "../../layouts";
import "./HomePage.css";

const HomePage = () => {
  return (
    <MainLayout>
      <div className="home-page">
        <h1>Trang chủ</h1>
        <p>Chào mừng bạn đến với hệ thống G-Bridge</p>
      </div>
    </MainLayout>
  );
};

export default HomePage;
